    81→                    <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill={isLiked ? 'rgb(255, 116, 116)' : "#5e5e5eff"}/>
    82→                    </g>
    83→                    </g>
    84→                </svg>
    85→            ),
    86→            
    87→            className: 'like-button',
    88→            action: (e, journalId, receiverId) => debounceClickLike(e, journalId, receiverId),
    89→            countLike: (count) => <p style={{padding:'0', margin: '0', fontSize: '0.8rem'}}>{formatCounts(count)}</p>
    90→        },
    91→        {
    92→            label: 
    93→            <svg className="svg-comment" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="#5e5e5eff">
    94→                <g id="style=fill">
    95→                <g id="comment">
    96→                <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M11.9862 0.763672C6.07454 0.763672 1.23621 5.36133 1.23621 11.1034C1.23621 13.5057 2.10188 15.7237 3.55066 17.4735C5.46882 19.8566 8.48271 21.3843 11.8522 21.4238L11.8878 21.4367C11.9902 21.4735 12.1385 21.5265 12.3236 21.5916C12.6936 21.7216 13.2115 21.9001 13.8035 22.0941C14.9799 22.4797 16.4767 22.9358 17.6892 23.1894C18.303 23.3178 18.9306 23.1718 19.4096 22.8608C19.8872 22.5507 20.3019 22.0126 20.3019 21.3173C20.3019 20.9046 20.1354 20.4987 19.9732 20.1857C19.8007 19.8529 19.5794 19.5251 19.371 19.2448C19.2691 19.1076 19.1676 18.9782 19.0724 18.8609C21.3193 16.9815 22.7362 14.2061 22.7362 11.1034C22.7362 7.55126 20.8865 4.4319 18.073 2.58609C16.3321 1.4227 14.2426 0.763672 11.9862 0.763672ZM18.3637 6.03728C18.1546 5.67972 17.6953 5.55937 17.3377 5.76847C16.9801 5.97757 16.8598 6.43694 17.0689 6.7945C17.8131 8.0671 18.2362 9.53599 18.2362 11.1034C18.2362 12.6662 17.8138 14.1316 17.0693 15.4016C16.8598 15.7589 16.9797 16.2184 17.337 16.4279C17.6943 16.6374 18.1538 16.5175 18.3633 16.1602C19.2385 14.6673 19.7362 12.941 19.7362 11.1034C19.7362 9.26158 19.238 7.53236 18.3637 6.03728Z" fill="#5e5e5eff"/>
    97→                </g>
    98→                </g>
    99→            </svg>,
   100→            className: 'comment-button',
   101→            commentAction: (e, jsonbContent, wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likeCount, bookmarkCount) => viewContent(e, jsonbContent, wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likeCount, bookmarkCount ),
   102→            countComments: (count) => <p style={{padding: '0', margin: '0', fontSize: '0.8rem'}}>{formatCounts(count)}</p>
   103→        },
   104→        {
   105→            checkBookrmark: (isBookmarked) => (
   106→            <svg className="svg-bookmark" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
   107→                <g id="style=fill">
   108→                    <g id="bookmark">
   109→                    <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={isBookmarked ? "rgb(72, 208, 135)" : "#5e5e5eff"}/>
   110→                    </g>
   111→                </g>
   112→            </svg>),
   113→            className: 'bookmark-button',
   114→            bookmarkAction: (e, journalId) => debounceClickBookmark(e, journalId),
   115→            countBookmarks: (count) => <p  style={{padding: '0', margin: '0', fontSize: '0.8rem'}}>{formatCounts(count)}</p>
   116→        },
   117→        {
   118→            iconCount: (count) => <p style={{padding: '0', margin: '0', fontSize: '0.6rem', color: "var(--icon-view-count)"}}>{formatCounts(count)}</p>,
   119→            iconView:
   120→            <svg xmlns="http://www.w3.org/2000/svg" fill="var(--icon-view)" width="28px" height="28px" viewBox="-3.5 0 32 32" version="1.1">
   121→                <title>view</title>
   122→                <path d="M12.406 13.844c1.188 0 2.156 0.969 2.156 2.156s-0.969 2.125-2.156 2.125-2.125-0.938-2.125-2.125 0.938-2.156 2.125-2.156zM12.406 8.531c7.063 0 12.156 6.625 12.156 6.625 0.344 0.438 0.344 1.219 0 1.656 0 0-5.094 6.625-12.156 6.625s-12.156-6.625-12.156-6.625c-0.344-0.438-0.344-1.219 0-1.656 0 0 5.094-6.625 12.156-6.625zM12.406 21.344c2.938 0 5.344-2.406 5.344-5.344s-2.406-5.344-5.344-5.344-5.344 2.406-5.344 5.344 2.406 5.344 5.344 5.344z"/>
   123→            </svg>,
   124→
   125→        }
   126→    ]
   127→
   128→    const userId = user?.userData?.[0]?.id || null;
   129→
   130→    const {
   131→        data,
   132→        fetchNextPage,
   133→        hasNextPage,
   134→        isFetchingNextPage,
   135→        isLoading,
   136→    } = useInfiniteQuery({
   137→        queryKey: ['journals', userId],
   138→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
   139→        getNextPageParam: (lastPage) => {
   140→            if(lastPage?.hasMore) {
   141→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
   142→                return new Date(lastJournal.created_at).toISOString();
   143→            }
   144→            return undefined;
   145→        } ,
   146→        refetchOnWindowFocus: false
   147→    })
   148→
   149→    const handleClickSettings = (e, postId) =>{
   150→        e.stopPropagation();
   151→        setPostIdSettings(postId === postIdSettings ? null : postId)
   152→    }
   153→
   154→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
   155→
   156→    const handleClickLike = async(e, journalId, receiverId) => {
   157→        e.stopPropagation();
   158→        if(!session) return openAuthModal();
   159→        console.log(journalId)
   160→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
   161→    }
   162→    const debounceClickLike = debounce(handleClickLike, 300)
   163→
   164→
   165→    const mutationBookmark = useBookMarkMutation(session);
   166→
   167→    const handleClickBookmark = async(e, journalId,) =>{
   168→        e.stopPropagation();
   169→        if(!session) return openAuthModal();
   170→        console.log(journalId)
   171→        // mutationBookmark.mutate({journalId});
   172→        const response = await mutationBookmark.mutateAsync({journalId})
   173→        if(response.message === 'success'){
   174→            setBookmarkedMessage('Post was added to your Bookmarks')
   175→            setShowBookmarkedMessage(journalId);
   176→            setTimeout(() =>{
   177→                setShowBookmarkedMessage(null)
   178→                setBookmarkedMessage('')
   179→            }, 2500)
   180→        } else {
   181→            setBookmarkedMessage('Post was removed from your Bookmarks')
   182→            setShowBookmarkedMessage(journalId);
   183→            setTimeout(() =>{
   184→                setShowBookmarkedMessage(null)
   185→                setBookmarkedMessage('')
   186→            }, 2500)
   187→        }
   188→        console.log(response.message);
   189→    }
   190→
   191→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
   192→
   193→
   194→    const isLoadingMore = isFetchingNextPage || !hasNextPage;
   195→    useEffect(() =>{
   196→        if(inView && !isLoadingMore) {
   197→            fetchNextPage();
   198→        }
   199→    }, [inView, fetchNextPage, isLoadingMore])
   200→
   201→
   202→    useEffect(() => {
   203→       const handleClickOutside = (e) =>{
   204→        if(modalRef.current && !modalRef.current.contains(e.target)){
   205→            setPostIdSettings(null)
   206→        }
   207→       }
   208→       window.addEventListener('click', handleClickOutside)
   209→
   210→       return() => {
   211→        window.removeEventListener('click', handleClickOutside)
   212→       }
   213→    }, [])
   214→
   215→    useEffect(() =>{
   216→        const scroll = (e) =>{
   217→            setShowHeaders(!showHeaders)
   218→
   219→            if(timeOutRef.current){
   220→                clearTimeout(timeOutRef.current);
   221→            }
   222→            timeOutRef.current = setTimeout(() => {
   223→                setShowHeaders(showHeaders)
   224→            }, 100);
   225→        }
   226→        document.addEventListener('scroll', scroll, true);
   227→        return() =>{
   228→            if(timeOutRef.current){
   229→                clearTimeout(timeOutRef.current);
   230→            }
   231→            document.removeEventListener('scroll', scroll, true)
   232→        }
   233→    }, [])
   234→
   235→    useEffect(() =>{
   236→        console.log(data)
   237→    }, [data])
   238→
   239→    const journals = data?.pages?.flatMap((page) => page.data || []) || [];
   240→
   241→    if(isLoading) {
   242→        return(
   243→            <>
   244→            <div className="postcards-parent-loading-container">
   245→                <MoonLoader loading={isLoading} color="rgba(0, 0, 0, 1)" speedMultiplier={1} size={20}/>
   246→            </div>
   247→            </>
   248→        )
   249→    }
   250→
   251→    if(journals?.length === 0 && !isLoading) {
   252→        return(
   253→            <div className="postcards-parent-container">
   254→                <div>No post availabe...</div>
   255→            </div>     
   256→        ) 
   257→    }
   258→    return(
   259→        <>
   260→        <AnimatePresence>
   261→            {showHeaders && (
   262→                <motion.div 
   263→                className="newsfeed-header"
   264→                initial={{opacity: 0}}
   265→                animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
   266→                exit={{ opacity: 0, y: -20,
   267→                        transition: { 
   268→                        duration: 0.2,
   269→                        ease: "easeOut"
   270→                        }
   271→                }}
   272→                >
   273→
   274→                    {header_links.map((header_link, index) => (
   275→                        <div key={index} className="header-links">
   276→                            <div onClick={() => handleClickHeaderLinks(header_link.path) } className='header-link'>
   277→                                {header_link.label}
   278→                                <div className={header_link.path === location.pathname ? "header-underline" : ''}/>
   279→                            </div>  
   280→                        </div>
   281→                    ))}
   282→
   283→                </motion.div>
   284→            )}
   285→            </AnimatePresence>
   286→        
   287→        <AnimatePresence>
   288→        <div className="postcards-parent-container">
   289→            {journals.map((journal, index) => {
   290→                const parsedContent = ParseContent(journal.content)
   291→                const isLiked = journal?.has_liked;
   292→                const isBookmarked = journal?.has_bookmarked;
   293→                return(
   294→                    <div className="cards" key={journal.id}>
   295→
   296→                        {parsedContent.firstImage && (
   297→                            <img
   298→                                className="card-image-banner"
   299→                                src={parsedContent.firstImage.src}
   300→                                alt=""
   301→                                loading="lazy"
   302→                                onClick={(e) => viewContent(e, journal.content, parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge)}
   303→                            />
   304→                        )}
   305→
   306→                        <div className="card-content">
   307→                            <div onClick={(e) => viewContent(e, journal.content, parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge)} className="content-container">
   308→                                <div className="feed-text-content-container">
   309→                                    <div className="feed-title-content">
   310→                                        <h2 className="feed-title">{journal.title.length > 40 ? `${journal.title.substring(0, 40)}...` : journal.title}</h2>
   311→                                    </div>
   312→                                    <p className="feed-text-content">{parsedContent.slicedText}</p>
   313→                                </div>
   314→                            </div>
   315→                        </div>
   316→
   317→                        <div className="card-icons-container">
   318→                            <div className="user-info-child-container">
   319→                                <div onClick={(e) => handleClickUserProfile(e, user?.userData?.[0].id, journal.users.id)} className={`user-avatar-container ${journal.users.badge === 'legend' ? 'avatar-ring-legend' : journal.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
   320→                                    <img loading="lazy" className="user-info-avatar" src={journal.users.image_url || '/assets/profile.jpg'} alt="" />
   321→                                </div>
   322→                                <div onClick={(e) => handleClickUserProfile(e, user?.userData?.[0].id, journal.users.id)} className="user-name-container">
   323→                                    <p className="user-newsfeed-name">{journal.users.name}</p>
   324→                                    <VerifiedBadge badge={journal.users.badge} size={14} />
   325→                                </div>
   326→                                <div className="name-info-separator">•</div>
   327→                                <p className="user-post-date">{formatPostDate(journal.created_at)}</p>
   328→                            </div>
   329→
   330→                            {cardIcons && (
   331→                                cardIcons.map((icon, index) =>(
   332→                                    <div key={index} className="icon-container">
   333→
   334→                                        {icon.likeAction && (
   335→                                            <div onClick={(e) => icon.action(e, journal.id, journal.users.id, user?.userData?.[0].image_url, user?.userData?.[0].name, user?.userData?.[0].user_email)} id="card-icons" className={icon.className}>
   336→                                                {icon.likeAction && icon.likeAction(isLiked)}
   337→                                            </div>
   338→                                        )}
   339→
   340→                                        {icon.commentAction && (
   341→                                            <div onClick={(e) => icon.commentAction(e, journal.content,parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count)} id="card-icons" className={icon.className}>
   342→                                                {icon.label}
   343→                                            </div>
   344→                                        )}
   345→
   346→                                        {icon.bookmarkAction && (
   347→                                            <div onClick={(e) => icon.bookmarkAction(e, journal.id)} className={icon.className}>
   348→                                                {icon.checkBookrmark(isBookmarked)}
   349→                                            </div>
   350→                                        )}
   351→
   352→                                        {icon.iconView && (
   353→                                            <div id="card-icons-view">
   354→                                                {icon.iconView}
   355→                                            </div>
   356→                                        )}
   357→
   358→                                        {icon.countLike && icon.countLike(journal.like_count?.[0].count)}
   359→                                        {icon.countComments && icon.countComments(journal.comment_count?.[0]?.count)}
   360→                                        {icon.countBookmarks && icon.countBookmarks(journal.bookmark_count?.[0].count)}
   361→                                        {icon.iconCount && icon.iconCount(journal?.views)}
   362→                                    </div>
   363→                                ))
   364→                            )}
   365→
   366→                            <div className="reading-time-container">
   367→                                <p className="reading-time-text">{CalculateText(parsedContent.wholeText)}</p>
   368→                            </div>
   369→
   370→                            <div className="user-post-settings">
   371→                                <svg onClick={(e) => handleClickSettings(e, journal.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
   372→                                {postIdSettings === journal.id && (
   373→                                    <motion.div
   374→                                    initial={{opacity:0 ,scale:0}}
   375→                                    animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
   376→                                    exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
   377→                                    ref={modalRef} className="setting-modal"
   378→                                    >
   379→                                        <p onClick={() => console.log('clicked')}>{journal.title}</p>
   380→                                    </motion.div>
   381→                                )}
   382→                            </div>
   383→                        </div>
   384→
   385→                        {showBookmarkedMessage === journal.id && (
   386→                            <motion.div
   387→                            className="bookmarked-content-message-container"
